import React from "react"
import {
  FormField,
  TextInput,
  TextArea,
  SelectField,
  PrimaryButton,
  FormStack,
} from "./common"
import { fieldKey } from "../utils/fieldKey"

export function DynamicForm({
  schema,
  values,
  onChange,
  onSubmit,
  submitLabel = `Save`,
  disabled = false,
}) {
  const fields = schema?.fields || []

  const handleChange = (key, value) => {
    onChange({ ...values, [key]: value })
  }

  return (
    <form
      onSubmit={(e) => {
        e.preventDefault()
        if (!disabled && typeof onSubmit === `function`) onSubmit(values)
      }}
      noValidate
    >
      <FormStack>
        {fields.map((f) => {
          const key = fieldKey(f)
          const label = f.label || key
          const required = !!f.required

          if (f.type === `textarea`) {
            return (
              <FormField key={f.id || key} label={label} htmlFor={key}>
                <TextArea
                  id={key}
                  name={key}
                  value={values[key] ?? ``}
                  onChange={(e) => handleChange(key, e.target.value)}
                  placeholder={f.placeholder || ``}
                  rows={f.rows && f.rows > 0 ? f.rows : 4}
                  required={required}
                  disabled={disabled}
                />
              </FormField>
            )
          }

          if (f.type === `select` && Array.isArray(f.options)) {
            return (
              <FormField key={f.id || key} label={label} htmlFor={key}>
                <SelectField
                  id={key}
                  name={key}
                  value={values[key] ?? ``}
                  onChange={(e) => handleChange(key, e.target.value)}
                  required={required}
                  disabled={disabled}
                >
                  {f.options.map((o) => (
                    <option key={o.value} value={o.value}>
                      {o.label || o.value}
                    </option>
                  ))}
                </SelectField>
              </FormField>
            )
          }

          if (f.type === `checkbox`) {
            return (
              <FormField key={f.id || key} label="" htmlFor={key}>
                <label className="checkbox-row">
                  <input
                    type="checkbox"
                    id={key}
                    name={key}
                    checked={!!values[key]}
                    onChange={(e) => handleChange(key, e.target.checked)}
                    disabled={disabled}
                  />
                  <span>{label}</span>
                </label>
              </FormField>
            )
          }

          const inputType =
            f.type === `email` ? `email` : f.type === `number` ? `number` : `text`

          return (
            <FormField key={f.id || key} label={label} htmlFor={key}>
              <TextInput
                id={key}
                name={key}
                type={inputType}
                value={values[key] ?? ``}
                onChange={(e) => handleChange(key, e.target.value)}
                placeholder={f.placeholder || ``}
                required={required}
                disabled={disabled}
              />
            </FormField>
          )
        })}

        <div>
          <PrimaryButton type="submit" disabled={disabled}>
            {submitLabel}
          </PrimaryButton>
        </div>
      </FormStack>
    </form>
  )
}
